    ("The projection of [3,4] onto [1,0] is:", ["[3,0]", "[0,4]", "[3,4]", "[1,0]"], 0, "proj = (3·1+4·0)/(1)·[1,0] = [3,0]."),
    ("If A is 3×3 with eigenvalues 1,1,2 then trace(A) =:", ["3", "4", "2", "6"], 1, "trace = 1+1+2 = 4."),
